                            { label: 'Atestado', list: resumoHoje.atestado, color: '#42A5F5', bg: 'rgba(66,165,245,0.15)' },
                            { label: 'F├®rias', list: resumoHoje.ferias, color: '#CE93D8', bg: 'rgba(206,147,216,0.15)' },
