                        ))}
                    </div>
                    {/* Lista r├ípida dos que N├âO est├úo seguindo a escala normal */}
                    {Object.keys(situacaoEspecial).filter(id => situacaoEspecial[id]).length > 0 && (
                        <div style={{ borderTop: '1px solid rgba(255,255,255,0.1)', paddingTop: '12px' }}>
                            <p style={{ fontSize: '11px', color: 'rgba(255,255,255,0.5)', marginBottom: '8px', fontWeight: '600' }}>ÔÜá ATEN├ç├âO ÔÇö Fora da Escala:</p>
                            {Object.keys(situacaoEspecial).filter(id => situacaoEspecial[id]).map(id => {
