                                    </div>
                                );
                            })}
                        </div>
                    )}
                </Card>

                {/* Cards de contagem */}
                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(140px, 1fr))', gap: '16px', marginBottom: '24px' }}>
                    <Card
