        mes = 2; // Fev
    } else {
        dia = i - 12;
        mes = 3; // Mar
    }
    const d = new Date(ano, mes - 1, dia);
    return {
        dia: dia,
        sem: DIAS_SEMANA_SHORT[d.getDay()]
    };
});

